// Calculate SERP share per keyword
const items = $input.all();
const ourRankings = items.filter(i => i.json.keyword_id).map(i => i.json);
const competitorRankings = items.filter(i => i.json.competitor_domain).map(i => i.json);

// Group competitor rankings by keyword
const compByKeyword = {};
competitorRankings.forEach(cr => {
  if (!compByKeyword[cr.keyword]) compByKeyword[cr.keyword] = {};
  compByKeyword[cr.keyword][cr.competitor_domain] = cr.position;
});

const today = new Date().toISOString().split('T')[0];

const results = ourRankings.map(our => {
  const competitorPositions = compByKeyword[our.keyword] || {};
  const competitorsInTop10 = Object.values(competitorPositions).filter(p => p && p <= 10).length;

  // Visibility score: 100 for position 1, decreasing logarithmically
  let visibilityScore = 0;
  if (our.our_position && our.our_position <= 100) {
    visibilityScore = Math.max(0, 100 - (Math.log10(our.our_position) * 50));
  }

  return {
    collected_date: today,
    keyword_id: our.keyword_id,
    keyword: our.keyword,
    our_position: our.our_position,
    our_url: our.our_url,
    total_competitors_in_top10: competitorsInTop10,
    our_visibility_score: Math.round(visibilityScore * 100) / 100,
    competitor_positions: competitorPositions
  };
});

return results.map(r => ({ json: r }));
